# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import json
from websockets import serve

# Initialize an empty inventory for each player
inventories = {}

async def handle_client(websocket):
    # Wait for client to send initial data (player's name and their inventory)
    player_name, inventory = await websocket.recv().split(':', 1)
    inventories[player_name] = json.loads(inventory)
    
    async for message in websocket:
        # Parse the client's request (e.g., "give item_id to player_name")
        action, target, item_id = message.split(' ')
        
        if action == 'give':
            # Give an item from this player's inventory to another
            inventories[target][item_id] += 1
            await websocket.send(f"You gave {item_id} to {target}.")
        elif action == 'take':
            # Take an item from another player's inventory
            if inventories[target][item_id] > 0:
                inventories[target][item_id] -= 1
                await websocket.send(f"You took {item_id} from {target}.")
            else:
                await websocket.send(f"{target} does not have any {item_id} left.")
        elif action == 'inventory':
            # Send the player's current inventory to them
            await websocket.send(json.dumps(inventories[player_name]))
        
async def main():
    async with serve('localhost', 8765):
        print("Starting server on localhost:8765")
        asyncio.run(handle_client())

if __name__ == "__main__":
    asyncio.run(main())